import{_ as e,c as o,o as i,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Guia de Melhores Práticas do AI App Factory: Descrição do Produto, Checkpoints, Escopo e Desenvolvimento Iterativo | Tutorial","description":"Domine as melhores práticas do AI App Factory para melhorar a qualidade e eficiência das aplicações geradas por IA. Aprenda a escrever descrições claras de produtos, utilizar checkpoints para controle de qualidade, definir claramente o escopo para evitar expansão, validar ideias gradualmente, economizar tokens dividindo sessões e lidar com falhas e novas tentativas. Este tutorial abrange seis técnicas essenciais: qualidade de entrada, confirmação de checkpoints, controle de MVP, desenvolvimento iterativo, otimização de contexto e tratamento de falhas.","frontmatter":{"title":"Guia de Melhores Práticas do AI App Factory: Descrição do Produto, Checkpoints, Escopo e Desenvolvimento Iterativo | Tutorial","sidebarTitle":"Melhores Práticas","subtitle":"Melhores Práticas: Descrições Claras, Aproveitamento de Checkpoints, Controle de Escopo e Técnicas de Iteração","description":"Domine as melhores práticas do AI App Factory para melhorar a qualidade e eficiência das aplicações geradas por IA. Aprenda a escrever descrições claras de produtos, utilizar checkpoints para controle de qualidade, definir claramente o escopo para evitar expansão, validar ideias gradualmente, economizar tokens dividindo sessões e lidar com falhas e novas tentativas. Este tutorial abrange seis técnicas essenciais: qualidade de entrada, confirmação de checkpoints, controle de MVP, desenvolvimento iterativo, otimização de contexto e tratamento de falhas.","tags":["Melhores Práticas","MVP","Desenvolvimento Iterativo"],"prerequisite":["start-getting-started","start-pipeline-overview"],"order":200},"headers":[],"relativePath":"pt/hyz1992/agent-app-factory/faq/best-practices/index.md","filePath":"pt/hyz1992/agent-app-factory/faq/best-practices/index.md"}'),s={name:"pt/hyz1992/agent-app-factory/faq/best-practices/index.md"};function r(n,a,d,l,c,p){return i(),o("div",null,[...a[0]||(a[0]=[t(`<h1 id="melhores-praticas-descricoes-claras-aproveitamento-de-checkpoints-controle-de-escopo-e-tecnicas-de-iteracao" tabindex="-1">Melhores Práticas: Descrições Claras, Aproveitamento de Checkpoints, Controle de Escopo e Técnicas de Iteração <a class="header-anchor" href="#melhores-praticas-descricoes-claras-aproveitamento-de-checkpoints-controle-de-escopo-e-tecnicas-de-iteracao" aria-label="Permalink to &quot;Melhores Práticas: Descrições Claras, Aproveitamento de Checkpoints, Controle de Escopo e Técnicas de Iteração&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><p>Ao concluir esta lição, você dominará:</p><ul><li>Como escrever descrições de produtos de alta qualidade para que a IA entenda suas ideias</li><li>Como utilizar o mecanismo de checkpoints para controlar a qualidade de cada fase</li><li>Como definir claramente os limites do escopo através de não-objetivos, evitando a expansão do projeto</li><li>Como validar ideias rapidamente e otimizar continuamente através de iterações graduais</li></ul><h2 id="os-desafios-que-voce-enfrenta" tabindex="-1">Os Desafios Que Você Enfrenta <a class="header-anchor" href="#os-desafios-que-voce-enfrenta" aria-label="Permalink to &quot;Os Desafios Que Você Enfrenta&quot;">​</a></h2><p>Você já se deparou com situações como estas?</p><ul><li>&quot;Fui muito claro, por que o resultado gerado não é o que eu queria?&quot;</li><li>&quot;Um detalhe não está satisfatório, e tudo o que vem depois está errado, é doloroso corrigir&quot;</li><li>&quot;Conforme avanço, as funcionalidades vão aumentando, e fica impossível finalizar&quot;</li><li>&quot;Quero implementar todas as funcionalidades de uma vez, mas no final não consigo fazer nada&quot;</li></ul><h2 id="quando-usar-estas-tecnicas" tabindex="-1">Quando Usar Estas Técnicas <a class="header-anchor" href="#quando-usar-estas-tecnicas" aria-label="Permalink to &quot;Quando Usar Estas Técnicas&quot;">​</a></h2><p>Seja você um usuário iniciante do AI App Factory ou já tenha alguma experiência, estas melhores práticas ajudarão você a:</p><ul><li><strong>Melhorar a qualidade do resultado</strong>: Fazer com que a aplicação gerada esteja mais alinhada com as expectativas</li><li><strong>Economizar tempo de correção</strong>: Evitar acúmulo de erros e detectar problemas no início</li><li><strong>Controlar o escopo do projeto</strong>: Focar no MVP e entregar rapidamente</li><li><strong>Reduzir custos de desenvolvimento</strong>: Validação em fases, evitando investimentos inválidos</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação Antes de Começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação Antes de Começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Pré-requisitos</p><ul><li>Ter lido <a href="./../../start/getting-started/">Início Rápido</a> para entender os conceitos básicos do AI App Factory</li><li>Ter lido <a href="./../../start/pipeline-overview/">Visão Geral do Pipeline de 7 Fases</a> para entender o fluxo completo</li><li>Ter completado pelo menos uma execução completa do pipeline (assim você terá uma sensação intuitiva do resultado de cada fase)</li></ul></div><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>As melhores práticas do AI App Factory giram em torno de quatro princípios fundamentais:</p><ol><li><strong>A qualidade da entrada determina a qualidade da saída</strong>: Descrições claras e detalhadas do produto são o primeiro passo para o sucesso</li><li><strong>Checkpoints são a linha de defesa da qualidade</strong>: Confirme cuidadosamente após a conclusão de cada fase para evitar acúmulo de erros</li><li><strong>Foco no MVP</strong>: Defina claramente os não-objetivos, controle o escopo e entregue rapidamente as funcionalidades principais</li><li><strong>Iteração contínua</strong>: Valide primeiro a ideia central e depois expanda gradualmente as funcionalidades</li></ol><p>Estes princípios são baseados em experiências práticas com código-fonte. Segui-los pode aumentar sua eficiência de desenvolvimento em várias vezes.</p><h2 id="siga-comigo" tabindex="-1">Siga Comigo <a class="header-anchor" href="#siga-comigo" aria-label="Permalink to &quot;Siga Comigo&quot;">​</a></h2><h3 id="tecnica-1-forneca-uma-descricao-clara-do-produto" tabindex="-1">Técnica 1: Forneça uma Descrição Clara do Produto <a class="header-anchor" href="#tecnica-1-forneca-uma-descricao-clara-do-produto" aria-label="Permalink to &quot;Técnica 1: Forneça uma Descrição Clara do Produto&quot;">​</a></h3><h4 id="por-que" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p>Quando a IA interpreta suas ideias, ela depende apenas das informações textuais que você fornece. Quanto mais clara a descrição, mais o resultado gerado estará alinhado com suas expectativas.</p><h4 id="como-fazer" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Uma boa descrição de produto contém os seguintes elementos</strong>:</p><ul><li><strong>Público-alvo</strong>: Quem usará este produto?</li><li><strong>Problema central</strong>: Que dificuldades o usuário está enfrentando?</li><li><strong>Solução</strong>: Como o produto resolve esta dificuldade?</li><li><strong>Funcionalidades-chave</strong>: Quais funcionalidades são obrigatórias?</li><li><strong>Cenários de uso</strong>: Em que situações o usuário utilizará o produto?</li><li><strong>Restrições</strong>: Há limitações ou requisitos especiais?</li></ul><h4 id="exemplos-comparativos" tabindex="-1">Exemplos Comparativos <a class="header-anchor" href="#exemplos-comparativos" aria-label="Permalink to &quot;Exemplos Comparativos&quot;">​</a></h4><table tabindex="0"><thead><tr><th>❌ Descrição Ruim</th><th>✅ Descrição Boa</th></tr></thead><tbody><tr><td>Criar um aplicativo de fitness</td><td>Aplicativo para ajudar iniciantes em fitness a registrar treinos, suportando registro de tipo de exercício, duração, calorias queimadas e visualização de estatísticas semanais de treino. O público-alvo são jovens que estão começando a se exercitar, as funcionalidades principais são registro rápido e acompanhamento de progresso, sem compartilhamento social ou funcionalidades pagas</td></tr><tr><td>Criar um aplicativo de controle financeiro</td><td>Aplicativo móvel para ajudar jovens a registrar despesas diárias rapidamente, com funcionalidades principais de registrar valor, selecionar categoria (alimentação, transporte, entretenimento, outros) e visualizar gastos totais do mês e estatísticas por categoria. Suporta uso offline, dados salvos apenas localmente</td></tr><tr><td>Criar uma ferramenta de gerenciamento de tarefas</td><td>Ferramenta simples para ajudar pequenas equipes a gerenciar tarefas, suportando criação de tarefas, atribuição de membros, definição de prazos e visualização de lista de tarefas. Membros da equipe podem compartilhar status de tarefas. Não requer fluxos de trabalho complexos ou gerenciamento de permissões</td></tr></tbody></table><h4 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h4><ul><li>[ ] A descrição define claramente o público-alvo</li><li>[ ] A descrição explica o problema central que o usuário enfrenta</li><li>[ ] A descrição lista as funcionalidades-chave (não mais que 5)</li><li>[ ] A descrição inclui restrições ou não-objetivos</li></ul><hr><h3 id="tecnica-2-confirme-cuidadosamente-nos-checkpoints" tabindex="-1">Técnica 2: Confirme Cuidadosamente nos Checkpoints <a class="header-anchor" href="#tecnica-2-confirme-cuidadosamente-nos-checkpoints" aria-label="Permalink to &quot;Técnica 2: Confirme Cuidadosamente nos Checkpoints&quot;">​</a></h3><h4 id="por-que-1" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que-1" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p>Após a conclusão de cada fase do pipeline, há uma pausa no checkpoint aguardando sua confirmação. Esta é a <strong>linha de defesa da qualidade</strong>, permitindo que você detecte problemas no início e evite que erros se propaguem para fases subsequentes.</p><p>Se um problema for detectado nesta fase, basta reexecutar a fase atual; se descoberto apenas no final, pode ser necessário reverter várias fases, desperdiçando muito tempo e tokens.</p><h4 id="como-fazer-1" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer-1" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Ao confirmar cada checkpoint, verifique o seguinte</strong>:</p><p><strong>Checkpoint da Fase Bootstrap</strong>:</p><ul><li>[ ] A definição do problema em <code>input/idea.md</code> está precisa</li><li>[ ] O perfil do usuário-alvo está claro e específico</li><li>[ ] A proposta de valor principal está definida</li><li>[ ] As suposições são razoáveis</li></ul><p><strong>Checkpoint da Fase PRD</strong>:</p><ul><li>[ ] As histórias de usuário estão claras, com condições de aceitação</li><li>[ ] A lista de funcionalidades não excede 7 itens (princípio do MVP)</li><li>[ ] Os não-objetivos (Non-Goals) estão claramente listados</li><li>[ ] Não inclui detalhes técnicos (como React, API, banco de dados)</li></ul><p><strong>Checkpoint da Fase UI</strong>:</p><ul><li>[ ] A estrutura das páginas é razoável, não mais que 3 páginas</li><li>[ ] O protótipo pode ser visualizado no navegador</li><li>[ ] O fluxo de interação está claro</li><li>[ ] O estilo visual é distinto (evita o estilo comum de IA)</li></ul><p><strong>Checkpoint da Fase Tech</strong>:</p><ul><li>[ ] A escolha da stack tecnológica é razoável e alinhada com o princípio do MVP</li><li>[ ] O design do modelo de dados é simples, não mais que 10 tabelas</li><li>[ ] A lista de endpoints da API está completa</li><li>[ ] Não introduz microsserviços, cache ou outros designs excessivos</li></ul><p><strong>Checkpoint da Fase Code</strong>:</p><ul><li>[ ] A estrutura do código frontend e backend está completa</li><li>[ ] Inclui casos de teste</li><li>[ ] Não há tipos <code>any</code> óbvios</li><li>[ ] Inclui README.md explicando como executar</li></ul><p><strong>Checkpoint da Fase Validation</strong>:</p><ul><li>[ ] O relatório de validação não contém problemas de segurança graves</li><li>[ ] A cobertura de testes é &gt; 60%</li><li>[ ] A instalação de dependências ocorre sem conflitos</li><li>[ ] A verificação de tipos TypeScript passa</li></ul><p><strong>Checkpoint da Fase Preview</strong>:</p><ul><li>[ ] O README.md contém instruções completas de execução</li><li>[ ] A configuração Docker pode ser construída normalmente</li><li>[ ] Os serviços frontend e backend podem ser iniciados localmente</li><li>[ ] Inclui instruções de configuração de variáveis de ambiente</li></ul><h4 id="fluxo-de-confirmacao-do-checkpoint" tabindex="-1">Fluxo de Confirmação do Checkpoint <a class="header-anchor" href="#fluxo-de-confirmacao-do-checkpoint" aria-label="Permalink to &quot;Fluxo de Confirmação do Checkpoint&quot;">​</a></h4><p>Em cada checkpoint, o sistema oferece as seguintes opções:</p><ul><li><strong>Continuar</strong>: Se o resultado estiver conforme o esperado, prossiga para a próxima fase</li><li><strong>Tentar Novamente</strong>: Se houver problemas no resultado, forneça feedback e reexecute a fase atual</li><li><strong>Pausar</strong>: Se precisar de mais informações ou quiser ajustar a ideia, pause o pipeline</li></ul><p><strong>Princípios de Decisão</strong>:</p><ul><li>✅ <strong>Continuar</strong>: Todos os itens de verificação atendem aos requisitos</li><li>⚠️ <strong>Tentar Novamente</strong>: Problemas menores (formato, omissões, detalhes) que podem ser corrigidos imediatamente</li><li>🛑 <strong>Pausar</strong>: Problemas graves (direção errada, escopo fora de controle, incapacidade de correção) que requerem replanejamento</li></ul><h4 id="alerta-de-armadilha" tabindex="-1">Alerta de Armadilha <a class="header-anchor" href="#alerta-de-armadilha" aria-label="Permalink to &quot;Alerta de Armadilha&quot;">​</a></h4><div class="danger custom-block"><p class="custom-block-title">Erro Comum</p><p><strong>Não pule a confirmação do checkpoint apenas para &quot;terminar logo&quot;!</strong></p><p>O pipeline foi projetado para &quot;pausar e confirmar em cada fase&quot; justamente para que você detecte problemas a tempo. Se você tiver o hábito de clicar em &quot;continuar&quot;, e só descobrir problemas no final, pode ser necessário:</p><ul><li>Reverter várias fases</li><li>Reexecutar grande parte do trabalho</li><li>Desperdiçar muitos tokens</li></ul><p>Lembre-se: <strong>O tempo investido na confirmação do checkpoint é muito menor que o custo de refazer tudo</strong>.</p></div><hr><h3 id="tecnica-3-utilize-nao-objetivos-para-controlar-o-escopo" tabindex="-1">Técnica 3: Utilize Não-Objetivos para Controlar o Escopo <a class="header-anchor" href="#tecnica-3-utilize-nao-objetivos-para-controlar-o-escopo" aria-label="Permalink to &quot;Técnica 3: Utilize Não-Objetivos para Controlar o Escopo&quot;">​</a></h3><h4 id="por-que-2" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que-2" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p><strong>Os não-objetivos (Non-Goals) são a arma principal do desenvolvimento MVP</strong>. Listar claramente o que &quot;não será feito&quot; pode efetivamente prevenir a expansão do escopo.</p><p>A raiz do fracasso de muitos projetos não é ter poucas funcionalidades, mas ter funcionalidades demais. Cada nova funcionalidade aumenta a complexidade, o tempo de desenvolvimento e os custos de manutenção. Definir limites claros e focar no valor central é a chave para entregar rapidamente.</p><h4 id="como-fazer-2" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer-2" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Na fase Bootstrap, liste claramente os não-objetivos</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Não-Objetivos (Funcionalidades Não Incluídas Nesta Versão)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">1.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não suporta colaboração multiusuário</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">2.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não suporta sincronização em tempo real</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">3.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não suporta integração com serviços de terceiros (como pagamento, mapas)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">4.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não fornece análise de dados ou funcionalidades de relatórios</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">5.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não inclui funcionalidades de compartilhamento social</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">6.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Não requer autenticação ou login de usuário</span></span></code></pre></div><p><strong>Na fase PRD, inclua os não-objetivos como um capítulo independente</strong>:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Não-Objetivos (Explicitamente Não Incluídos Nesta Versão)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">As seguintes funcionalidades, embora valiosas, não estão no escopo deste MVP:</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Funcionalidade | Motivo | Planejamento Futuro |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| --- | --- | --- |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Colaboração multiusuário | Foco em usuários individuais | Considerar na v2.0 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Sincronização em tempo real | Aumenta complexidade técnica | Considerar se houver feedback forte dos usuários |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Integração de pagamento | Não é valor central | Considerar na v1.5 |</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">| Análise de dados | Não necessário para MVP | Considerar na v2.0 |</span></span></code></pre></div><h4 id="criterios-de-julgamento-para-nao-objetivos" tabindex="-1">Critérios de Julgamento para Não-Objetivos <a class="header-anchor" href="#criterios-de-julgamento-para-nao-objetivos" aria-label="Permalink to &quot;Critérios de Julgamento para Não-Objetivos&quot;">​</a></h4><p><strong>Como determinar se algo deve ser um não-objetivo</strong>:</p><ul><li>❌ Esta funcionalidade não é essencial para validar a ideia central → Defina como não-objetivo</li><li>❌ Esta funcionalidade aumentará significativamente a complexidade técnica → Defina como não-objetivo</li><li>❌ Esta funcionalidade pode ser substituída por métodos manuais → Defina como não-objetivo</li><li>✅ Esta funcionalidade é a razão de existir do produto → Deve ser incluída</li></ul><h4 id="alerta-de-armadilha-1" tabindex="-1">Alerta de Armadilha <a class="header-anchor" href="#alerta-de-armadilha-1" aria-label="Permalink to &quot;Alerta de Armadilha&quot;">​</a></h4><div class="warning custom-block"><p class="custom-block-title">Armadilha de Expansão de Escopo</p><p><strong>Sinais comuns de expansão de escopo</strong>:</p><ol><li>&quot;Já que é simples, vou adicionar rapidamente...&quot;</li><li>&quot;Os concorrentes têm esta funcionalidade, nós também precisamos...&quot;</li><li>&quot;Os usuários podem precisar, é melhor fazer logo...&quot;</li><li>&quot;Esta funcionalidade é interessante, pode destacar o produto...&quot;</li></ol><p><strong>Quando tiver essas ideias, faça três perguntas</strong>:</p><ol><li>Esta funcionalidade é útil para validar a ideia central?</li><li>Se não fizer esta funcionalidade, o produto ainda funcionará?</li><li>Adicionar esta funcionalidade vai atrasar a entrega?</li></ol><p>Se as respostas forem &quot;não&quot;, &quot;sim&quot; e &quot;sim&quot;, então coloque-a decididamente nos não-objetivos.</p></div><hr><h3 id="tecnica-4-iteracao-gradual-e-validacao-rapida" tabindex="-1">Técnica 4: Iteração Gradual e Validação Rápida <a class="header-anchor" href="#tecnica-4-iteracao-gradual-e-validacao-rapida" aria-label="Permalink to &quot;Técnica 4: Iteração Gradual e Validação Rápida&quot;">​</a></h3><h4 id="por-que-3" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que-3" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p><strong>O conceito central do MVP (Produto Mínimo Viável) é validar ideias rapidamente</strong>, não fazer tudo perfeito de uma vez.</p><p>Através do desenvolvimento iterativo, você pode:</p><ul><li>Obter feedback dos usuários no início</li><li>Ajustar a direção a tempo</li><li>Reduzir custos irrecuperáveis</li><li>Manter o impulso de desenvolvimento</li></ul><h4 id="como-fazer-3" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer-3" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Etapas do desenvolvimento iterativo</strong>:</p><p><strong>Primeira Rodada: Validação da Funcionalidade Central</strong></p><ol><li>Use o AI App Factory para gerar a primeira versão da aplicação</li><li>Inclua apenas as 3-5 funcionalidades mais centrais</li><li>Execute e teste rapidamente</li><li>Mostre o protótipo a usuários reais e colete feedback</li></ol><p><strong>Segunda Rodada: Otimização Baseada no Feedback</strong></p><ol><li>Com base no feedback dos usuários, determine os pontos de melhoria de maior prioridade</li><li>Modifique <code>input/idea.md</code> ou <code>artifacts/prd/prd.md</code></li><li>Use <code>factory run &lt;stage&gt;</code> para reexecutar a partir da fase correspondente</li><li>Gere a nova versão e teste</li></ol><p><strong>Terceira Rodada: Expansão de Funcionalidades</strong></p><ol><li>Avalie se os objetivos centrais foram alcançados</li><li>Selecione 2-3 funcionalidades de alto valor</li><li>Gere e integre através do pipeline</li><li>Continue iterando e refinando gradualmente</li></ol><h4 id="exemplo-pratico-de-iteracao" tabindex="-1">Exemplo Prático de Iteração <a class="header-anchor" href="#exemplo-pratico-de-iteracao" aria-label="Permalink to &quot;Exemplo Prático de Iteração&quot;">​</a></h4><p><strong>Cenário</strong>: Você quer criar um aplicativo de gerenciamento de tarefas</p><p><strong>Primeira Rodada MVP</strong>:</p><ul><li>Funcionalidades centrais: criar tarefas, visualizar lista, marcar como concluída</li><li>Não-objetivos: gerenciamento de membros, controle de permissões, notificações de lembrete</li><li>Tempo de entrega: 1 dia</li></ul><p><strong>Segunda Rodada de Otimização</strong> (baseada no feedback):</p><ul><li>Feedback dos usuários: querem adicionar etiquetas às tarefas</li><li>Modificar o PRD, adicionar funcionalidade de &quot;classificação por etiquetas&quot;</li><li>Reexecutar o pipeline a partir da fase UI</li><li>Tempo de entrega: meio dia</li></ul><p><strong>Terceira Rodada de Expansão</strong> (após validação bem-sucedida):</p><ul><li>Adicionar funcionalidade de gerenciamento de membros</li><li>Adicionar lembretes de prazos</li><li>Adicionar funcionalidade de comentários em tarefas</li><li>Tempo de entrega: 2 dias</li></ul><h4 id="checkpoint-✅-1" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅-1" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h4><p>Antes de cada iteração, verifique:</p><ul><li>[ ] A nova funcionalidade está alinhada com o objetivo central</li><li>[ ] A nova funcionalidade tem suporte de demanda dos usuários</li><li>[ ] A nova funcionalidade aumentará significativamente a complexidade</li><li>[ ] Há critérios de aceitação claros</li></ul><hr><h2 id="tecnicas-avancadas" tabindex="-1">Técnicas Avançadas <a class="header-anchor" href="#tecnicas-avancadas" aria-label="Permalink to &quot;Técnicas Avançadas&quot;">​</a></h2><h3 id="tecnica-5-economize-tokens-dividindo-sessoes" tabindex="-1">Técnica 5: Economize Tokens Dividindo Sessões <a class="header-anchor" href="#tecnica-5-economize-tokens-dividindo-sessoes" aria-label="Permalink to &quot;Técnica 5: Economize Tokens Dividindo Sessões&quot;">​</a></h3><h4 id="por-que-4" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que-4" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p>Executar o pipeline por longos períodos leva ao acúmulo de contexto, consumindo muitos tokens. <strong>A execução em sessões divididas</strong> permite que cada fase tenha um contexto limpo e exclusivo, reduzindo significativamente os custos de uso.</p><h4 id="como-fazer-4" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer-4" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Em cada checkpoint, escolha &quot;Continuar em Nova Sessão&quot;</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Execute em uma nova janela de terminal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">factory</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> continue</span></span></code></pre></div><p>O sistema automaticamente:</p><ol><li>Lê <code>.factory/state.json</code> para restaurar o estado</li><li>Inicia uma nova janela do Claude Code</li><li>Continua a partir da próxima fase a ser executada</li><li>Carrega apenas os arquivos de entrada necessários para aquela fase</li></ol><p><strong>Comparação</strong>:</p><table tabindex="0"><thead><tr><th>Método</th><th>Vantagens</th><th>Desvantagens</th></tr></thead><tbody><tr><td>Continuar na Mesma Sessão</td><td>Simples, não precisa trocar de janela</td><td>Acúmulo de contexto, alto consumo de tokens</td></tr><tr><td>Nova Sessão</td><td>Cada fase tem contexto limpo exclusivo, economiza tokens</td><td>Precisa trocar de janela</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Prática Recomendada</p><p><strong>Para projetos grandes ou com orçamento limitado de tokens, recomendamos fortemente o uso de &quot;Continuar em Nova Sessão&quot;</strong>.</p><p>Para instruções detalhadas, consulte o tutorial de <a href="./../../advanced/context-optimization/">Otimização de Contexto</a>.</p></div><hr><h3 id="tecnica-6-lidar-com-falhas-e-novas-tentativas" tabindex="-1">Técnica 6: Lidar com Falhas e Novas Tentativas <a class="header-anchor" href="#tecnica-6-lidar-com-falhas-e-novas-tentativas" aria-label="Permalink to &quot;Técnica 6: Lidar com Falhas e Novas Tentativas&quot;">​</a></h3><h4 id="por-que-5" tabindex="-1">Por Quê <a class="header-anchor" href="#por-que-5" aria-label="Permalink to &quot;Por Quê&quot;">​</a></h4><p>Durante a execução do pipeline, podem ocorrer falhas (entrada insuficiente, problemas de permissão, erros de código, etc.). Entender como lidar com falhas permite que você recupere o progresso mais rapidamente.</p><h4 id="como-fazer-5" tabindex="-1">Como Fazer <a class="header-anchor" href="#como-fazer-5" aria-label="Permalink to &quot;Como Fazer&quot;">​</a></h4><p><strong>Melhores práticas para tratamento de falhas</strong> (referência <code>failure.policy.md:267-274</code>):</p><ol><li><strong>Falha Antecipada</strong>: Detecte problemas o mais cedo possível para evitar desperdiçar tempo em fases subsequentes</li><li><strong>Logs Detalhados</strong>: Registre informações de contexto suficientes para facilitar a investigação de problemas</li><li><strong>Operações Atômicas</strong>: A saída de cada fase deve ser atômica, facilitando o rollback</li><li><strong>Preservar Evidências</strong>: Arquive os produtos de falha antes de tentar novamente, facilitando análise comparativa</li><li><strong>Tentativas Graduais</strong>: Ao tentar novamente, forneça orientações mais específicas em vez de simplesmente repetir</li></ol><p><strong>Cenários Comuns de Falha</strong>:</p><table tabindex="0"><thead><tr><th>Tipo de Falha</th><th>Sintoma</th><th>Solução</th></tr></thead><tbody><tr><td>Saída Ausente</td><td><code>input/idea.md</code> não existe</td><td>Tentar novamente, verificar caminho de escrita</td></tr><tr><td>Expansão de Escopo</td><td>Número de funcionalidades &gt; 7</td><td>Tentar novamente, solicitar redução para MVP</td></tr><tr><td>Erro Técnico</td><td>Falha na compilação TypeScript</td><td>Verificar definições de tipos, tentar novamente</td></tr><tr><td>Problema de Permissão</td><td>Agente tenta escrever em diretório não autorizado</td><td>Verificar matriz de limites de capacidade</td></tr></tbody></table><p><strong>Lista de Verificação para Recuperação de Falhas</strong>:</p><ul><li>[ ] A causa da falha foi identificada</li><li>[ ] A solução de correção foi implementada</li><li>[ ] As configurações relevantes foram atualizadas</li><li>[ ] Reiniciar a partir da fase que falhou</li></ul><div class="tip custom-block"><p class="custom-block-title">Falhas São Normais</p><p><strong>Não tenha medo de falhas!</strong> O AI App Factory foi projetado com um mecanismo completo de tratamento de falhas:</p><ul><li>Cada fase permite uma tentativa automática</li><li>Produtos de falha são automaticamente arquivados em <code>artifacts/_failed/</code></li><li>É possível reverter para o checkpoint de sucesso mais recente</li></ul><p>Ao encontrar uma falha, analise calmamente a causa e siga a estratégia de falha apropriada.</p></div><hr><h2 id="resumo-da-licao" tabindex="-1">Resumo da Lição <a class="header-anchor" href="#resumo-da-licao" aria-label="Permalink to &quot;Resumo da Lição&quot;">​</a></h2><p>Esta lição apresentou as seis melhores práticas do AI App Factory:</p><ol><li><strong>Descrição Clara do Produto</strong>: Descreva detalhadamente o público-alvo, problema central, funcionalidades-chave e restrições</li><li><strong>Confirmação Cuidadosa nos Checkpoints</strong>: Verifique a qualidade da saída após cada fase para evitar acúmulo de erros</li><li><strong>Utilize Não-Objetivos para Controlar o Escopo</strong>: Liste claramente as funcionalidades que não serão feitas para prevenir expansão do escopo</li><li><strong>Iteração Gradual</strong>: Valide primeiro a ideia central e depois expanda gradualmente com base no feedback dos usuários</li><li><strong>Economize Tokens Dividindo Sessões</strong>: Crie novas sessões em cada checkpoint para reduzir custos</li><li><strong>Trate Falhas Corretamente</strong>: Utilize o mecanismo de tratamento de falhas para recuperar o progresso rapidamente</li></ol><p>Seguindo estas melhores práticas, sua experiência com o AI App Factory será mais fluida, a qualidade das aplicações geradas será maior e a eficiência de desenvolvimento aumentará em várias vezes.</p><hr><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos sobre a <a href="./../../appendix/cli-commands/">Referência de Comandos CLI</a>.</p><p>Você vai aprender:</p><ul><li>Todos os parâmetros e opções do comando <code>factory init</code></li><li>Como o comando <code>factory run</code> inicia a partir de uma fase específica</li><li>Como o comando <code>factory continue</code> cria uma nova sessão para continuar</li><li>Como <code>factory status</code> e <code>factory list</code> visualizam informações do projeto</li><li>Como <code>factory reset</code> redefine o estado do projeto</li></ul></blockquote><hr><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código-Fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código-Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Última atualização: 2026-01-29</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Técnicas de Descrição do Produto</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L186-L210" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>186-210</td></tr><tr><td>Mecanismo de Checkpoints</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md#L98-L112" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>98-112</td></tr><tr><td>Controle de Não-Objetivos</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/README.md#L199-L203" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>199-203</td></tr><tr><td>Estratégia de Tratamento de Falhas</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md#L267-L274" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>267-274</td></tr><tr><td>Isolamento de Contexto</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/context-isolation.md#L10-L42" target="_blank" rel="noreferrer"><code>policies/context-isolation.md</code></a></td><td>10-42</td></tr><tr><td>Padrões de Código</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>Completo</td></tr></tbody></table><p><strong>Constantes Principais</strong>:</p><ul><li><code>MAX_RETRY_COUNT = 1</code>: Cada fase permite uma tentativa automática por padrão</li></ul><p><strong>Regras Principais</strong>:</p><ul><li>Quantidade de funcionalidades Must Have ≤ 7 (princípio do MVP)</li><li>Quantidade de páginas ≤ 3 (fase UI)</li><li>Quantidade de modelos de dados ≤ 10 (fase Tech)</li><li>Cobertura de testes &gt; 60% (fase Validation)</li></ul></details>`,131)])])}const h=e(s,[["render",r]]);export{m as __pageData,h as default};
